import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote base premiums (per price list)
  it.todo("should quote base premium for a single sword (new customer, first contract)");
  it.todo("should quote base premium for a single amulet");
  it.todo("should quote base premium for a single staff");
  it.todo("should quote base premium for a single potion");
  it.todo("should quote base premium for a single component (rune)");
  it.todo("should quote a building block of 3 alike components at special premium");

  // Quote modifiers
  it.todo("should apply 50% cursed surcharge");
  it.todo("should apply 30% high-enchantment surcharge (enchantment >= 5)");
  it.todo("should apply 20% loyalty discount for customers with >= 2 years");
  it.todo("should apply 15% discount on each contract after the first");

  // Claims
  it.todo("should pay claim amount minus 100 G deductible for ordinary damage");
  it.todo("should reimburse 50% for damage to highly enchanted items (enchantment >= 8)");
  it.todo("should fully reimburse damage to dragon material items");
  it.todo("should cap total payout per policy at twice the insurance sum");
});

