export type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

export type Step =
  | { op: "quote"; items: Item[] }
  | { op: "claim"; policy: number; incident: any };

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type StepResult =
  | { premium: number }
  | { payout: number; remainingCap: number };

export type ScenarioResult = {
  results: StepResult[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PCT = 10;

// Round up in MHPCO's favor: applies percent surcharge/discount via integer math.
const applyPercent = (amount: number, percent: number): number =>
  Math.ceil((amount * (100 + percent)) / 100);

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const base = BASE_PREMIUMS[step.items[0].type];
      const adjusted = applyPercent(base, FIRST_INSURANCE_SURCHARGE_PCT);
      return { premium: adjusted + PROCESSING_FEE };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

