type Policy = {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
};

const insuranceSumFor = (items: Item[]): number =>
  items.reduce(
    (sum, item) =>
      sum +
      (item.kind === "component"
        ? COMPONENT_INSURANCE_VALUE
        : INSURANCE_VALUES[item.type]),
    0,
  );

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies: Policy[] = [];
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFirst = quoteCount === 0;
      quoteCount++;
      const insuranceSum = insuranceSumFor(step.items);
      policies.push({
        items: step.items,
        insuranceSum,
        remainingCap: insuranceSum * CAP_MULTIPLIER,
      });
      return {
        premium: quotePremium(step.items, scenario.customer, isFirst),
      };
    }
    // claim
    const policy = policies[step.policy];
    const damageTotal = step.incident.damages.reduce(
      (sum, d) => sum + d.amount,
      0,
    );
    const reimbursable = Math.max(0, damageTotal - DEDUCTIBLE);
    const payout = Math.min(reimbursable, policy.remainingCap);
    policy.remainingCap -= payout;
    return { payout, remainingCap: policy.remainingCap };
  });
  return { results };
};

